     */
    @Parameter(property = "description", readonly = true)
    private String description;

    /**
     * {@inheritDoc}
     */
    @Override
    public String getName(Locale locale) {
        if (StringUtils.isEmpty(name)) {
            return getBundle(locale).getString("report.scoverage.name");
        }
        return name;
    }

    /**
     * {@inheritDoc}
